// 架构伪代码：DMA 循环缓冲区的三层接口定义

/* Layer 1: DMA 配置 */
typedef struct {
    DMA_HandleTypeDef hdma;
    UART_HandleTypeDef *huart;
} dma_uart_ctx_t;

void dma_uart_init(dma_uart_ctx_t *ctx, UART_HandleTypeDef *huart,
                   uint8_t *buf, uint16_t buf_size);

/* Layer 2: 环形缓冲区 */
typedef struct {
    volatile uint16_t head;
    volatile uint16_t tail;
    uint8_t *data;
    uint16_t mask;  // buf_size - 1, 用于位运算取模
} ring_buf_t;

uint16_t ring_buf_available(const ring_buf_t *rb);
uint16_t ring_buf_read(ring_buf_t *rb, uint8_t *out, uint16_t len);

/* Layer 3: 应用回调 */
void dma_uart_rx_complete(dma_uart_ctx_t *ctx);

/* 关键：缓冲区大小必须是 2 的幂 */
#define RING_BUF_SIZE 512  // 512 = 0x200, mask = 0x1FF

/* ring_buffer.h - DMA 循环缓冲区头文件 */
#ifndef RING_BUFFER_H
#define RING_BUFFER_H

#include <stdint.h>
#include <string.h>

#define RING_BUF_SIZE 512
#define RING_BUF_MASK (RING_BUF_SIZE - 1)  // 0x1FF

typedef struct {
    volatile uint16_t head;    /* DMA 写入位置 */
    volatile uint16_t tail;    /* 应用读取位置 */
    uint8_t data[RING_BUF_SIZE];
} ring_buf_t;

static inline void ring_buf_init(ring_buf_t *rb) {
    rb->head = 0;
    rb->tail = 0;
}

/* 返回缓冲区中未读字节数 */
static inline uint16_t ring_buf_count(const ring_buf_t *rb) {
    uint16_t h = rb->head, t = rb->tail;
    return (h >= t) ? (h - t) : (RING_BUF_SIZE - t + h);
}

/* 读取数据，最多读 len 字节，返回实际读取数 */
static inline uint16_t ring_buf_read(ring_buf_t *rb, uint8_t *out,
                                      uint16_t len) {
    uint16_t avail = ring_buf_count(rb);
    if (len > avail) len = avail;
    for (uint16_t i = 0; i < len; i++) {
        out[i] = rb->data[(rb->tail + i) & RING_BUF_MASK];
    }
    rb->tail = (rb->tail + len) & RING_BUF_MASK;
    return len;
}

#endif /* RING_BUFFER_H */

/* uart_dma.c - DMA 接收实现 */
#include "ring_buffer.h"
#include "stm32f1xx_hal.h"

static ring_buf_t uart2_ring;
static uint8_t dma_rx_buf[RING_BUF_SIZE];

void uart_dma_rx_init(UART_HandleTypeDef *huart) {
    ring_buf_init(&uart2_ring);
    /* 启动 DMA 循环接收：DMA1_Channel5, UART2_RX */
    HAL_DMA_Start_IT(huart->hdmarx,
                     (uint32_t)&huart->Instance->DR,
                     (uint32_t)dma_rx_buf,
                     RING_BUF_SIZE);
    /* 开启 UART DMA 接收 */
    __HAL_UART_ENABLE_DMA(huart, UART_DMA_RECEIVE);
}

/* DMA 传输完成回调 - 由 HAL 在中上下文中调用 */
void HAL_DMA_TxCpltCallback(DMA_HandleTypeDef *hdma) {
    /* 第 1 步：先拷贝 DMA 缓冲区数据到环形缓冲区 */
    for (uint16_t i = 0; i < RING_BUF_SIZE; i++) {
        uart2_ring.data[uart2_ring.head] = dma_rx_buf[i];
        uart2_ring.head = (uart2_ring.head + 1) & RING_BUF_MASK;
    }
    /* 第 2 步：如果缓冲区溢出（head 追上 tail），丢弃最旧数据 */
    if (ring_buf_count(&uart2_ring) > RING_BUF_SIZE) {
        uart2_ring.tail = uart2_ring.head;
    }
    /* 注意：不需要重新调用 HAL_DMA_Start_IT，
     * 循环模式下 DMA 会自动重启 */
}

/* 陷阱 1 的修复示例：正确的 volatile 使用 */
typedef struct {
    volatile uint16_t head;
    volatile uint16_t tail;
    uint8_t data[RING_BUF_SIZE];
} ring_buf_t;

/* 陷阱 2 的修复示例：双缓冲区 ping-pong */
#define PING_PONG_SIZE (RING_BUF_SIZE / 2)
static uint8_t ping_buf[PING_PONG_SIZE];
static uint8_t pong_buf[PING_PONG_SIZE];
static volatile uint8_t *active_buf = ping_buf;
static volatile uint8_t *free_buf = pong_buf;
static volatile uint8_t swap_needed = 0;

void HAL_DMA_TxCpltCallback(DMA_HandleTypeDef *hdma) {
    /* 切换缓冲区：DMA 开始写 free_buf，CPU 读 active_buf */
    swap_needed = 1;
    /* 不立即交换，等主循环中安全地交换 */
}

/* 主循环中 */
if (swap_needed) {
    swap_needed = 0;
    uint8_t *tmp = active_buf;
    active_buf = free_buf;
    free_buf = tmp;
    /* 现在可以安全地处理 active_buf 中的数据 */
    process_data(active_buf, PING_PONG_SIZE);
    /* 重新启动 DMA 写入新的 free_buf */
    HAL_DMA_Start_IT(huart->hdmarx,
                     (uint32_t)&huart->Instance->DR,
                     (uint32_t)free_buf,
                     PING_PONG_SIZE);
}

/* ===== 重构前：轮询式 UART 接收（坏味道：重复、紧耦合）=====
 * 问题：
 * 1. 每个字节都要读 DR 寄存器，CPU 满载
 * 2. 没有缓冲区，丢字节时无处保存
 * 3. 业务逻辑和硬件操作混在一起
 */
void uart_poll_receive(void) {
    while (1) {
        if (huart2.Instance->SR & USART_SR_RXNE) {
            uint8_t byte = huart2.Instance->DR;  /* 读数据寄存器 */
            process_byte(byte);                   /* 业务逻辑耦合 */
            if (byte == 0x0A) break;              /* 换行结束 */
        }
    }
}

/* ===== 重构后：DMA + 环形缓冲区（改进：解耦、可扩展）=====
 * 改进：
 * 1. DMA 硬件搬运，CPU 仅在缓冲区满时介入
 * 2. 环形缓冲区作为生产者-消费者之间的缓冲层
 * 3. 业务逻辑通过回调函数注入，不直接操作硬件
 */
typedef struct {
    ring_buf_t ring;
    void (*rx_callback)(uint8_t *data, uint16_t len);
    UART_HandleTypeDef *huart;
} dma_uart_t;

static dma_uart_t uart2_ctx;

void dma_uart_init(dma_uart_t *ctx, UART_HandleTypeDef *huart,
                   void (*cb)(uint8_t*, uint16_t)) {
    ring_buf_init(&ctx->ring);
    ctx->rx_callback = cb;
    ctx->huart = huart;
    HAL_DMA_Start_IT(huart->hdmarx,
                     (uint32_t)&huart->Instance->DR,
                     (uint32_t)ctx->ring.data,
                     RING_BUF_SIZE);
    __HAL_UART_ENABLE_DMA(huart, UART_DMA_RECEIVE);
}

/* DMA 完成回调：仅做数据搬运，不含业务逻辑 */
void HAL_DMA_TxCpltCallback(DMA_HandleTypeDef *hdma) {
    dma_uart_t *ctx = &uart2_ctx;
    /* 将 DMA 缓冲区数据移入环形缓冲区 */
    uint16_t count = ring_buf_count(&ctx->ring);
    if (count > 0 && ctx->rx_callback) {
        uint8_t temp[RING_BUF_SIZE];
        uint16_t n = ring_buf_read(&ctx->ring, temp, count);
        ctx->rx_callback(temp, n);  /* 回调处理业务逻辑 */
    }
}

/* 使用示例：业务层只关心数据，不关心 DMA */
void my_rx_handler(uint8_t *data, uint16_t len) {
    for (uint16_t i = 0; i < len; i++) {
        if (data[i] == 0x0A) {
            /* 处理一行完整数据 */
            parse_line(data, i);
            data += i + 1;
            len -= i + 1;
            i = 0;
        }
    }
}
